  <script>
    const labels = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    const actual = [42, 46, 44, 51, 54, 58, 61, 65, 68, 72, 79, 84];
    const forecast = [null,null,null,null,null,null,null,null,70,76,82,89];
    let sortDir = 1;
    let chart;

function currentSlice() {
      const count = parseInt(document.getElementById('rangeSelect').value, 10);
      return {
        labels: labels.slice(-count),
        actual: actual.slice(-count),
        forecast: forecast.slice(-count)
      };
    }

function buildChart() {
      const slice = currentSlice();
      chart = new Chart(document.getElementById('revChart'), {
        type: 'line',
        data: {
          labels: slice.labels,
          datasets: [
            {
              label: 'Revenue ($k)',
              data: slice.actual,
              borderColor: '#6366f1',
              backgroundColor: 'rgba(99,102,241,0.12)',
              tension: 0.35,
              fill: true,
              pointRadius: 3
            },
            {
              label: 'Forecast ($k)',
              data: document.getElementById('modeToggle').checked ? slice.forecast : [],
              borderColor: '#f59e0b',
              borderDash: [6,6],
              tension: 0.35,
              fill: false,
              pointRadius: 3
            }
          ]
        },
        options: {
          responsive: true,
          maintainAspectRatio: false,
          plugins: { legend: { labels: { color: 'rgba(127,127,127,0.9)' } } },
          scales: {
            x: { ticks: { color: 'rgba(127,127,127,0.9)' }, grid: { color: 'rgba(127,127,127,0.12)' } },
            y: { ticks: { color: 'rgba(127,127,127,0.9)' }, grid: { color: 'rgba(127,127,127,0.12)' } }
          }
        }
      });
    }

function updateChart() {
      const slice = currentSlice();
      chart.data.labels = slice.labels;
      chart.data.datasets[0].data = slice.actual;
      chart.data.datasets[1].data = document.getElementById('modeToggle').checked ? slice.forecast : [];
      chart.update();
    }

function toggleMode() { updateChart(); }

function filterRows() {
      const q = document.getElementById('search').value.toLowerCase();
      document.querySelectorAll('#tbody tr').forEach(r => {
        r.style.display = r.textContent.toLowerCase().includes(q) ? '' : 'none';
      });
    }

function sortTable(col) {
      const tbody = document.getElementById('tbody');
      const rows = [...tbody.querySelectorAll('tr')];
      rows.sort((a,b) => {
        const av = a.cells[col].textContent.replace(/[$,%+]/g,'').trim();
        const bv = b.cells[col].textContent.replace(/[$,%+]/g,'').trim();
        const an = parseFloat(av), bn = parseFloat(bv);
        return (isNaN(an) || isNaN(bn) ? av.localeCompare(bv) : an - bn) * sortDir;
      });
      sortDir *= -1;
      rows.forEach(r => tbody.appendChild(r));
    }

buildChart();
